query:
SELECT cv.id as cv_id, cv.userId, cv.type, cv.visibleCVtheque,
       u.id as user_id, u.name as user_name, u.email, u.profileType
FROM cv_documents cv
LEFT JOIN users u ON cv.userId = u.id
WHERE cv.userId = 60001;

SELECT id, name, email, profileType FROM users WHERE id = 60001;
SELECT id, name, email, profileType FROM users ORDER BY id DESC LIMIT 10;

